// Command encoders

/// Encode SetpointRaiseLower command (0x00)
pub fn encode_setpoint_raise_lower(mode: SetpointRaiseLowerMode, amount: i8) -> anyhow::Result<Vec<u8>> {
    let tlv = tlv::TlvItemEnc {
        tag: 0,
        value: tlv::TlvItemValueEnc::StructInvisible(vec![
        (0, tlv::TlvItemValueEnc::UInt8(mode.to_u8())).into(),
        (1, tlv::TlvItemValueEnc::Int8(amount)).into(),
        ]),
    };
    Ok(tlv.encode()?)
}

/// Encode SetActiveScheduleRequest command (0x05)
pub fn encode_set_active_schedule_request(schedule_handle: Vec<u8>) -> anyhow::Result<Vec<u8>> {
    let tlv = tlv::TlvItemEnc {
        tag: 0,
        value: tlv::TlvItemValueEnc::StructInvisible(vec![
        (0, tlv::TlvItemValueEnc::OctetString(schedule_handle)).into(),
        ]),
    };
    Ok(tlv.encode()?)
}

/// Encode SetActivePresetRequest command (0x06)
pub fn encode_set_active_preset_request(preset_handle: Option<Vec<u8>>) -> anyhow::Result<Vec<u8>> {
    let tlv = tlv::TlvItemEnc {
        tag: 0,
        value: tlv::TlvItemValueEnc::StructInvisible(vec![
        (0, tlv::TlvItemValueEnc::OctetString(preset_handle.unwrap_or(vec![]))).into(),
        ]),
    };
    Ok(tlv.encode()?)
}

/// Encode AddThermostatSuggestion command (0x07)
pub fn encode_add_thermostat_suggestion(preset_handle: Vec<u8>, effective_time: Option<u64>, expiration_in_minutes: u16) -> anyhow::Result<Vec<u8>> {
    let tlv = tlv::TlvItemEnc {
        tag: 0,
        value: tlv::TlvItemValueEnc::StructInvisible(vec![
        (0, tlv::TlvItemValueEnc::OctetString(preset_handle)).into(),
        (1, tlv::TlvItemValueEnc::UInt64(effective_time.unwrap_or(0))).into(),
        (2, tlv::TlvItemValueEnc::UInt16(expiration_in_minutes)).into(),
        ]),
    };
    Ok(tlv.encode()?)
}

/// Encode RemoveThermostatSuggestion command (0x08)
pub fn encode_remove_thermostat_suggestion(unique_id: u8) -> anyhow::Result<Vec<u8>> {
    let tlv = tlv::TlvItemEnc {
        tag: 0,
        value: tlv::TlvItemValueEnc::StructInvisible(vec![
        (0, tlv::TlvItemValueEnc::UInt8(unique_id)).into(),
        ]),
    };
    Ok(tlv.encode()?)
}

